using Microsoft.VisualStudio.TestTools.UnitTesting;
using Store;

namespace Tests;

[TestClass]
public class ShoppingCartTests
{
    private ShoppingCart _cart = null!;

    [TestInitialize]
    public void Setup()
    {
        _cart = new ShoppingCart();
    }

    // --- AddItem Tests ---

    [TestMethod]
    public void AddItem_SingleItem_IncreasesTotal()
    {
        _cart.AddItem("SKU-001", 2, 10.00m);

        Assert.AreEqual(20.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_MultipleDistinctItems_SumsCorrectly()
    {
        _cart.AddItem("SKU-001", 1, 5.00m);
        _cart.AddItem("SKU-002", 3, 7.50m);

        Assert.AreEqual(27.50m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_SameSkuTwice_CombinesQuantities()
    {
        _cart.AddItem("SKU-001", 1, 10.00m);
        _cart.AddItem("SKU-001", 2, 10.00m);

        // Expect 3 * 10 = 30
        Assert.AreEqual(30.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_ZeroQuantity_DoesNotAffectTotal()
    {
        _cart.AddItem("SKU-001", 0, 10.00m);

        Assert.AreEqual(0.00m, _cart.CalculateTotal());
    }

    // --- RemoveItem Tests ---

    [TestMethod]
    public void RemoveItem_ExistingItem_RemovesFromTotal()
    {
        _cart.AddItem("SKU-001", 2, 10.00m);
        _cart.AddItem("SKU-002", 1, 5.00m);

        _cart.RemoveItem("SKU-001");

        Assert.AreEqual(5.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void RemoveItem_NonexistentSku_DoesNotThrow()
    {
        _cart.AddItem("SKU-001", 1, 10.00m);

        // Should not throw for unknown SKU
        _cart.RemoveItem("SKU-999");

        Assert.AreEqual(10.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void RemoveItem_AllItems_ResultsInZeroTotal()
    {
        _cart.AddItem("SKU-001", 1, 15.00m);
        _cart.RemoveItem("SKU-001");

        Assert.AreEqual(0.00m, _cart.CalculateTotal());
    }

    // --- CalculateTotal Tests ---

    [TestMethod]
    public void CalculateTotal_EmptyCart_ReturnsZero()
    {
        Assert.AreEqual(0.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_AfterAddAndRemove_ReflectsCurrentState()
    {
        _cart.AddItem("A", 2, 10.00m);
        _cart.AddItem("B", 1, 25.00m);
        _cart.RemoveItem("A");

        Assert.AreEqual(25.00m, _cart.CalculateTotal());
    }

    // --- ApplyCoupon Tests ---

    [TestMethod]
    public void ApplyCoupon_ValidCode_ReducesTotal()
    {
        _cart.AddItem("SKU-001", 1, 100.00m);
        _cart.ApplyCoupon("SAVE10");

        var total = _cart.CalculateTotal();
        Assert.IsTrue(total < 100.00m, $"Expected discounted total, got {total}");
    }

    [TestMethod]
    public void ApplyCoupon_InvalidCode_TotalUnchanged()
    {
        _cart.AddItem("SKU-001", 1, 50.00m);
        _cart.ApplyCoupon("BOGUS");

        Assert.AreEqual(50.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void ApplyCoupon_EmptyCart_DoesNotThrow()
    {
        _cart.ApplyCoupon("SAVE10");

        Assert.AreEqual(0.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void ApplyCoupon_AppliedTwice_OnlyDiscountsOnce()
    {
        _cart.AddItem("SKU-001", 1, 100.00m);
        _cart.ApplyCoupon("SAVE10");
        var firstTotal = _cart.CalculateTotal();

        _cart.ApplyCoupon("SAVE10");
        var secondTotal = _cart.CalculateTotal();

        Assert.AreEqual(firstTotal, secondTotal);
    }
}

